boot.shared:
// 三载体用同一 v4 原生 API；widget 应把 data.targets 解析为自身 shadow 内 Element
import { animate } from 'https://cdn.jsdelivr.net/npm/animejs@4/+esm';
const p = data.parameters;
const animation = animate(data.targets, { ...p, duration: p.duration ?? 1000, delay: p.delay ?? 0,
  ease: p.ease ?? 'out(2)', loop: p.loop ?? false, autoplay: p.autoplay ?? true });
